#include<bits/stdc++.h>
using namespace std;
int a[100010];
int main()
{
    int n;
    vector<int> s1,s2;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    s1.push_back(0);
    s2.push_back(0);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        while(s1.size()>1&&a[s1.back()]>=a[i])
        {
            s1.pop_back();
        }
        while(s2.size()>1&&a[s2.back()]<a[i])
        {
            s2.pop_back();
        }
        auto pos=upper_bound(s1.begin(),s1.end(),s2.back());
        if(pos!=s1.end())
        {
            ans=max(ans,i-(*pos)+1);
        }
        s1.push_back(i);
        s2.push_back(i);
    }
    printf("%d",ans);
    return 0;
}
